            // trailing 優先、なければ params フォールバック。
            "PING" => {
                let token = parsed.trailing.clone().or_else(|| {
                    let j = parsed.params.join(" ");
                    if j.is_empty() { None } else { Some(j) }
                }).unwrap_or_default();
                result.reply = Some(format!("PONG :{}", token));
